import React, { useEffect } from "react";
import { useNavigate } from "react-router-dom";
import "../styles/Dashboard.css";
import avatar from "../assets/dashboard-avatar.png";
import { speak } from "../utils/speak";

function Dashboard() {
  const navigate = useNavigate();

  useEffect(() => {
    speak(
      "Welcome back. I am here to support you. Please choose how I can help you today."
    );
  }, []);

  return (
    <div className="dashboard-wrapper">
      
      {/* AVATAR SECTION */}
      <div className="dashboard-avatar">
        <img src={avatar} alt="Therapist Avatar" />
        <h2>Welcome to MindCare AI</h2>
        <p>Your safe mental health companion</p>
      </div>

      {/* FEATURE CARDS */}
      <div className="dashboard-grid">
        <div className="feature-card" onClick={() => navigate("/chat")}>
          💬 General Chat
        </div>

        <div className="feature-card" onClick={() => navigate("/history")}>
          📜 Chat History
        </div>

        <div className="feature-card" onClick={() => navigate("/mood")}>
          😊 Mood Tracker
        </div>

        <div className="feature-card" onClick={() => navigate("/sleep")}>
          😴 Sleep Tracker
        </div>

        <div className="feature-card crisis" onClick={() => navigate("/crisis")}>
          🚨 Crisis Support
        </div>

        <div className="feature-card logout" onClick={() => navigate("/")}>
          🔓 Logout
        </div>
      </div>

    </div>
  );
}

export default Dashboard;
